mapper.select:

WHERE r.post_id = #{postId}
  AND r.status = 1
ORDER BY r.created_at ASC, r.id ASC


WHERE 1 = 1

  AND r.id = #{id}


  AND r.post_id = #{postId}


  AND (r.content ILIKE '%' || #{keyword} || '%' OR p.title ILIKE '%' || #{keyword} || '%')


  AND r.status = #{status}

ORDER BY r.status DESC, r.created_at DESC, r.id DESC
